import React from 'react';
import Header from '../components/header/header';
import Footer from '../components/Footer/Footer';
import { ResolvedContentProvider } from '../ppm/util/ResolvedContentContext';
import { STATIC_MUSIC_ALBUMS } from '../contexts/db/music-albums';
import '../global.css';

const MusicPage = () => {
  return (
    <ResolvedContentProvider>
      <div className="media-page">
        <Header />
        <div style={{ height: '120px' }} />
        
        <main className="media-container">
          <header className="media-header">
            <h1>Thư viện Âm nhạc</h1>
          </header>

          <div className="media-grid">
            {STATIC_MUSIC_ALBUMS.map((album) => {
              const fallbackImage = album.tracks?.find(t => t.image)?.image || album.tracks?.find(t => t.imageFile)?.imageFile;
              const imageUrl = album.thumbnail || fallbackImage;
              return (
              <div key={album.id} className="media-card music-card">
                <div className="media-thumb music-thumb">
                  {imageUrl ? (
                    <img src={imageUrl.startsWith('http') || imageUrl.startsWith('/') ? imageUrl : `/images/${imageUrl}`} alt={album.name} onError={(e) => { e.currentTarget.style.display = 'none'; }} />
                  ) : (
                    <div className="placeholder-thumb music-placeholder">
                       <span>🎵</span>
                    </div>
                  )}
                </div>
                <div className="media-info">
                  <h3>{album.name}</h3>
                  <p>{(album as any).category || 'Album'}</p>
                </div>
              </div>
            )})}
          </div>

        </main>
        
        <Footer />

        <style dangerouslySetInnerHTML={{ __html: `
          .media-page {
            background-color: #f5f3ee;
            min-height: 100vh;
          }
          .media-container {
            max-width: 1200px;
            margin: 0 auto;
            padding: 40px 20px;
          }
          .media-header {
            margin-bottom: 40px;
            border-bottom: 2px solid #E6B422;
            padding-bottom: 20px;
          }
          .media-header h1 {
            font-family: 'Playfair Display', serif;
            color: #1a1a1a;
            margin: 0;
          }
          .media-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
            gap: 30px;
          }
          .media-card {
            background: white;
            border-radius: 12px;
            overflow: hidden;
            box-shadow: 0 4px 15px rgba(0,0,0,0.05);
            transition: transform 0.3s ease;
          }
          .media-card:hover {
            transform: translateY(-5px);
          }
          .music-thumb {
            aspect-ratio: 1/1;
            background: #f0f0f0;
          }
          .music-thumb img {
            width: 100%;
            height: 100%;
            object-fit: cover;
          }
          .music-placeholder {
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 60px;
            height: 100%;
          }
          .media-info {
            padding: 20px;
            text-align: center;
          }
          .media-info h3 {
            margin: 0 0 8px 0;
            font-size: 18px;
            color: #1a1a1a;
            font-family: 'Playfair Display', serif;
          }
          .media-info p {
            margin: 0;
            font-size: 13px;
            color: #E6B422;
            font-weight: 600;
            letter-spacing: 1px;
          }
        `}} />
      </div>
    </ResolvedContentProvider>
  );
};

export default MusicPage;
